import React, { useState, useEffect, useCallback } from "react";
import "./PDFAnalyzer.css";

function PDFAnalyzer({ onPdfSelect }) {
  const [selectedPDF, setSelectedPDF] = useState("");
  const [pdfs, setPdfs] = useState([]);
  const [sections, setSections] = useState({
    summary: "",
    hospitalization: "",
    riskClassifier: "",
    recommendations: "",
    keyInsights: "",
  });
  const [chatContent, setChatContent] = useState("");
  const [chatResponse, setChatResponse] = useState("");

  // Use useCallback to memoize the fetchPDFs function
  const fetchPDFs = useCallback(async () => {
    try {
      const response = await fetch("http://localhost:8000/pdfs");
      const data = await response.json();
      console.log("Fetched PDFs:", data);
      if (Array.isArray(data.pdf_files)) {
        setPdfs(data.pdf_files);
      } else {
        console.error("Unexpected data structure:", data);
        setPdfs([]);
      }
    } catch (error) {
      console.error("Error fetching PDFs:", error);
      setPdfs([]);
    }
  }, []); // Empty dependency array means this function won't change between renders

  // Use useEffect with the memoized fetchPDFs
  useEffect(() => {
    fetchPDFs();
  }, [fetchPDFs]);

  // Memoize handlePDFSelect to prevent unnecessary re-renders
  const handlePDFSelect = useCallback((pdf) => {
    setSelectedPDF(pdf);
    // Only call onPdfSelect if it's a function
    if (typeof onPdfSelect === 'function') {
      onPdfSelect(pdf);
    }
  }, [onPdfSelect]);

  // Memoize handleRunAnalysis to prevent unnecessary re-renders
  const handleRunAnalysis = useCallback(async () => {
    if (!selectedPDF) return;

    const sectionNames = [
      "summary",
      "hospitalization",
      "riskClassifier",
      "recommendations",
      "keyInsights",
    ];
    const updatedSections = { ...sections };

    for (const section of sectionNames) {
      try {
        const response = await fetch("http://localhost:8000/analyze-section", {
          method: "POST",
          headers: {
            "Content-Type": "application/json",
          },
          body: JSON.stringify({
            pdf: selectedPDF,
            section: section,
          }),
        });
        const data = await response.json();
        updatedSections[section] = data.content || "No data available";
      } catch (error) {
        console.error(`Error fetching analysis for ${section}:`, error);
        updatedSections[section] = "Error fetching data";
      }
    }

    setSections(updatedSections);
  }, [selectedPDF, sections]);

  return (
    <div className="analyzer-container">
      <div className="header">
        <h1>IBM WatsonX APS Application</h1>
      </div>

      <div className="controls">
        <select
          className="applicant-select"
          value={selectedPDF}
          onChange={(e) => handlePDFSelect(e.target.value)}
        >
          <option value="">Select an Applicant</option>
          {pdfs.map((pdf) => (
            <option key={pdf} value={pdf}>
              {pdf}
            </option>
          ))}
        </select>

        <button 
          className="run-button" 
          onClick={handleRunAnalysis}
          disabled={!selectedPDF}
        >
          Run Analysis
        </button>
      </div>

      {/* Rest of the component remains the same */}
    </div>
  );
}

// Use React.memo to prevent unnecessary re-renders of the entire component
export default React.memo(PDFAnalyzer);
